 6 /// Resolve the CIABATTA_* build variables from the local git repository rooted
 7 /// at (or containing) `root`. Used by `--local` and `ciabatta source` so the
 8 /// same recipes work on a developer machine without a CI system.
 9 ///
10 ///   CIABATTA_BRANCH        current branch (omitted when HEAD is detached)
11 ///   CIABATTA_COMMIT        full HEAD commit SHA
12 ///   CIABATTA_TAG           tag pointing exactly at HEAD, if any
13 ///   CIABATTA_BUILD_NUMBER  commit count reachable from HEAD (a local stand-in)
14 pub fn local_git_vars(root: &Path) -> Result<HashMap<String, String>> {
15     if run_git(root, &["rev-parse", "--is-inside-work-tree"]).is_err() {
16         bail!(
17             "'{}' is not inside a git repository; local mode needs local git history.",
18             root.display()
19         );
20     }
21 
22     let mut vars = HashMap::new();
23 
24     // Branch: skip the literal "HEAD" you get in a detached-HEAD checkout.
25     if let Ok(branch) = run_git(root, &["rev-parse", "--abbrev-ref", "HEAD"])
26         && !branch.is_empty()
27         && branch != "HEAD"
28     {
29         vars.insert("CIABATTA_BRANCH".to_string(), branch);
30     }
31 
32     if let Ok(commit) = run_git(root, &["rev-parse", "HEAD"])
33         && !commit.is_empty()
34     {
35         vars.insert("CIABATTA_COMMIT".to_string(), commit);
36     }
37 
38     // Only present when HEAD is exactly a tag (the command fails otherwise).
39     if let Ok(tag) = run_git(root, &["describe", "--tags", "--exact-match"])
40         && !tag.is_empty()

 45     if let Ok(count) = run_git(root, &["rev-list", "--count", "HEAD"])
 46         && !count.is_empty()
 47     {
 48         vars.insert("CIABATTA_BUILD_NUMBER".to_string(), count);
 49     }
 50 
 51     Ok(vars)
 52 }
