 54 /// List up to `limit` commit SHAs reachable from `refname` (a branch, tag, or
 55 /// commit), most recent first. Used by the pull best-hash fallback to walk a
 56 /// branch's history looking for the newest commit that has a published artifact.
 57 pub fn branch_commits(root: &Path, refname: &str, limit: usize) -> Result<Vec<String>> {
 58     let max = limit.to_string();
 59     let out = run_git(root, &["rev-list", "--max-count", &max, refname])?;
 60     Ok(out
 61         .lines()
 62         .map(|l| l.trim().to_string())
 63         .filter(|l| !l.is_empty())
 64         .collect())
 65 }
