 67 /// The well-known SHA of git's empty tree, used as a diff base when the repo is
 68 /// younger than the requested window (so we can still show the full change set).
 69 const EMPTY_TREE: &str = "4b825dc642cb6eb9a060e54bf8d69288fbee4904";
 70 
 71 /// Summarize git activity over the past `days` days as plain text: the commit
 72 /// list, the committed diffstat for the window, and any uncommitted changes.
 73 /// Used by `ciabatta ai report` and the TUI `/report` command to give the
 74 /// assistant something to explain.
 75 pub fn changes_since(root: &Path, days: u64) -> Result<String> {
 76     if run_git(root, &["rev-parse", "--is-inside-work-tree"]).is_err() {
 77         bail!(
 78             "'{}' is not inside a git repository — a report needs local git history.",
 79             root.display()
 80         );
 81     }
 82     let since = format!("--since={days} days ago");
 83     let before = format!("--before={days} days ago");
 84 
 85     // Commit list within the window (short hash, date, subject, author).
 86     let log = run_git(
 87         root,
 88         &["log", &since, "--pretty=format:%h %ad %s (%an)", "--date=short"],
 89     )
 90     .unwrap_or_default();
 91 
 92     // Committed changes: diff from the last commit *before* the window to HEAD.
 93     // If nothing predates the window, diff from the empty tree (full history).
 94     let base = run_git(root, &["rev-list", "-1", &before, "HEAD"]).unwrap_or_default();
 95     let base = if base.is_empty() { EMPTY_TREE.to_string() } else { base };
 96     let stat = run_git(root, &["diff", "--stat", &base, "HEAD"]).unwrap_or_default();
 97 
 98     // Uncommitted working-tree changes (staged + unstaged) relative to HEAD.
 99     let uncommitted = run_git(root, &["diff", "--stat", "HEAD"]).unwrap_or_default();
100 
101     if log.is_empty() && stat.is_empty() && uncommitted.is_empty() {
102         return Ok(format!("No git activity in the past {days} day(s)."));
103     }
104 
105     let mut out = String::new();
106     out.push_str(&format!("Commits (past {days} day(s)):\n"));
107     out.push_str(if log.is_empty() { "(none)" } else { &log });
108     out.push_str("\n\nFiles changed (committed in window):\n");
109     out.push_str(if stat.is_empty() { "(none)" } else { &stat });
110     if !uncommitted.is_empty() {
111         out.push_str("\n\nUncommitted working-tree changes:\n");
112         out.push_str(&uncommitted);
113     }
114     Ok(clip(&out, 16_000))

  1 //! A tiny, dependency-free PDF writer for change reports.
  2 //!
  3 //! Generating a real PDF normally means a heavy crate or an external tool
  4 //! (pandoc, headless Chrome). We only need to lay plain text onto pages, so we
  5 //! emit a minimal but valid PDF by hand: monospaced Courier (one of PDF's
  6 //! built-in base-14 fonts, so nothing to embed), hard-wrapped to a fixed column
  7 //! count, paginated. The result opens in any PDF viewer.
  8 
  9 use std::path::Path;
 10 
 11 use anyhow::{Context, Result};
