 13 /// Characters per line and lines per page, tuned for Courier 10pt on US Letter
 14 /// (612×792 pt) with comfortable margins.
 15 const COLS: usize = 80;
 16 const ROWS_PER_PAGE: usize = 56;
 17 
 18 /// Write a change report to `path` as a PDF: a title, timestamp, the assistant's
 19 /// summary, and (when non-empty) the raw git activity as an appendix.
 20 pub fn write_report(path: &Path, days: u64, summary: &str, activity: &str) -> Result<()> {
 21     let mut lines: Vec<String> = Vec::new();
 22     push_wrapped(&mut lines, &format!("Repository change report — past {days} day(s)"));
 23     push_wrapped(
 24         &mut lines,
 25         &format!("Generated {}", chrono::Local::now().format("%Y-%m-%d %H:%M")),
 26     );
 27     lines.push(String::new());
 28     lines.push("== Summary ==".to_string());
 29     for line in summary.lines() {
 30         push_wrapped(&mut lines, line);
 31     }
 32     if !activity.trim().is_empty() {
 33         lines.push(String::new());
 34         lines.push("== Git activity ==".to_string());
 35         for line in activity.lines() {
 36             push_wrapped(&mut lines, line);
 37         }
 38     }
 39 
 40     let bytes = build_pdf(&lines);
 41     std::fs::write(path, bytes).with_context(|| format!("failed to write {}", path.display()))
 42 }
 43 
 44 /// Hard-wrap one logical line to `COLS` columns, pushing each piece. Non-ASCII
 45 /// and control characters are handled at render time; here we only split.
 46 fn push_wrapped(out: &mut Vec<String>, line: &str) {
 47     let line = line.replace('\t', "    ");
 48     if line.is_empty() {
 49         out.push(String::new());
 50         return;
 51     }
 52     let chars: Vec<char> = line.chars().collect();
 53     for chunk in chars.chunks(COLS) {
 54         out.push(chunk.iter().collect());
 55     }
 56 }
 57 
 58 /// Assemble the PDF byte stream from already-wrapped text lines.
 59 fn build_pdf(text_lines: &[String]) -> Vec<u8> {
 60     let pages: Vec<&[String]> = if text_lines.is_empty() {
 61         vec![&[]]
 62     } else {
 63         text_lines.chunks(ROWS_PER_PAGE).collect()
 64     };
 65     let page_count = pages.len();
 66 
 67     // Object 1: catalog, 2: pages, 3: font, then a (page, content) pair each.
 68     let mut objects: Vec<String> = Vec::new();
 69     objects.push("<< /Type /Catalog /Pages 2 0 R >>".to_string());
 70     let kids: String = (0..page_count)
 71         .map(|p| format!("{} 0 R", 4 + 2 * p))
 72         .collect::<Vec<_>>()
 73         .join(" ");
 74     objects.push(format!("<< /Type /Pages /Kids [{kids}] /Count {page_count} >>"));
 75     objects.push("<< /Type /Font /Subtype /Type1 /BaseFont /Courier >>".to_string());
 76 
 77     for page in &pages {
 78         let content_obj = 5 + 2 * objects_pages_so_far(&objects);
 79         objects.push(format!(
 80             "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] \
 81              /Resources << /Font << /F1 3 0 R >> >> /Contents {content_obj} 0 R >>"
 82         ));
 83 
 84         // Start near the top; T* steps down by the leading (TL) each line.
 85         let mut stream = String::from("BT\n/F1 10 Tf\n12 TL\n50 760 Td\n");
 86         for line in page.iter() {
 87             stream.push('(');
 88             stream.push_str(&escape(line));
 89             stream.push_str(") Tj\nT*\n");
 90         }
 91         stream.push_str("ET");
 92         objects.push(format!("<< /Length {} >>\nstream\n{stream}\nendstream", stream.len()));
 93     }
 94 
 95     // Serialize with a cross-reference table.
 96     let mut out: Vec<u8> = Vec::new();
 97     out.extend_from_slice(b"%PDF-1.4\n");
 98     let mut offsets = vec![0usize; objects.len() + 1];
 99     for (i, body) in objects.iter().enumerate() {
100         let num = i + 1;
101         offsets[num] = out.len();
102         out.extend_from_slice(format!("{num} 0 obj\n").as_bytes());
103         out.extend_from_slice(body.as_bytes());
104         out.extend_from_slice(b"\nendobj\n");
105     }
106     let xref_offset = out.len();
107     let size = objects.len() + 1;
108     out.extend_from_slice(format!("xref\n0 {size}\n").as_bytes());
109     out.extend_from_slice(b"0000000000 65535 f \n");
110     for num in 1..size {
111         out.extend_from_slice(format!("{:010} 00000 n \n", offsets[num]).as_bytes());
112     }
113     out.extend_from_slice(
114         format!("trailer\n<< /Size {size} /Root 1 0 R >>\nstartxref\n{xref_offset}\n%%EOF\n")
115             .as_bytes(),
116     );
117     out
118 }
