120 /// How many page objects have been pushed so far (each page adds two objects,
121 /// after the first three fixed ones), so we can compute the next content ref.
122 fn objects_pages_so_far(objects: &[String]) -> usize {
123     // objects: [catalog, pages, font, page0, content0, page1, content1, ...]
124     objects.len().saturating_sub(3) / 2
125 }
