127 /// Escape a line for a PDF literal string and drop anything that isn't printable
128 /// ASCII (Courier's default encoding), so the stream stays valid.
129 fn escape(s: &str) -> String {
130     let mut o = String::with_capacity(s.len());
131     for c in s.chars() {
132         match c {
133             '\\' => o.push_str("\\\\"),
134             '(' => o.push_str("\\("),
135             ')' => o.push_str("\\)"),
136             c if (0x20..=0x7e).contains(&(c as u32)) => o.push(c),
137             // Map the common non-ASCII punctuation that shows up in prose to a
138             // sensible ASCII equivalent, so it reads right in Courier.
139             '—' | '–' => o.push('-'),
140             '“' | '”' | '„' => o.push('"'),
141             '‘' | '’' | '‚' => o.push('\''),
142             '…' => o.push_str("..."),
143             '•' => o.push('*'),
144             '→' => o.push_str("->"),
145             _ => o.push('?'),
146         }
147     }
148     o
149 }
