155     #[test]
156     fn writes_a_valid_looking_pdf() {
157         let dir = std::env::temp_dir().join(format!("ciabatta-pdf-{}", std::process::id()));
158         std::fs::create_dir_all(&dir).unwrap();
159         let path = dir.join("report.pdf");
160 
161         // A long summary forces multiple pages.
162         let summary = (0..200).map(|i| format!("change number {i}")).collect::<Vec<_>>().join("\n");
163         write_report(&path, 7, &summary, "abc123 fix: thing\n src/x.rs | 2 +-").unwrap();
164 
165         let bytes = std::fs::read(&path).unwrap();
166         assert!(bytes.starts_with(b"%PDF-1.4"), "missing PDF header");
167         assert!(bytes.ends_with(b"%%EOF\n"), "missing EOF marker");
168         // Header, xref, trailer present and multi-page.
169         let text = String::from_utf8_lossy(&bytes);
170         assert!(text.contains("/Type /Catalog"));
171         assert!(text.contains("startxref"));
172         assert!(text.contains("/Count "));
173         // Parentheses in content are escaped, not raw-broken.
174         write_report(&path, 1, "value is (parenthesized) here", "").unwrap();
175         let text2 = String::from_utf8_lossy(&std::fs::read(&path).unwrap()).to_string();
176         assert!(text2.contains("\\(parenthesized\\)"));
177 
178         // Common non-ASCII punctuation is mapped to ASCII, not dropped to '?'.
179         assert_eq!(escape("a — b … c"), "a - b ... c");
180         assert_eq!(escape("“q” ‘r’"), "\"q\" 'r'");
181 
182         let _ = std::fs::remove_dir_all(&dir);
183     }
184 }
